import { isFunction } from '../utils/function-utils';
import { mathSQRT, NULL } from './zc-constants';
import { d3_zc as d3 } from './d3-constants';
import { isObject } from '../utils/zcutils';

//$Id$
//d3polyfill.js
d3.rebind = function(target, source) {
    var i = 1,
        n = arguments.length,
        method;
    while (++i < n) {
        target[(method = arguments[i])] = rebindMethods(target, source, source[method]);
    }
    return target;
};
function rebindMethods(target, source, method) {
    return function() {
        var value = method.apply(source, arguments);
        return value === source ? target : value;
    };
}

// find all the points within radius
(function(d3) {
    // the idea has taken from here https://bl.ocks.org/enjalot/778182a0cae1c2ff60186f7e7c1d350f
    d3.quadtree.prototype.findAll = function(x, y, radius, sizeOffset) {
        var tree = this,
            points = {
                points: [],
                visited: []
            };

        tree._size =
            tree._size ||
            function() {
                return 0;
            };

        // object is rectangle
        if (isObject(radius)) {
            // radius is extent [[x1 y1], [x2, y2]]
            tree.visit(withinRect(radius, points.points, points.visited, tree));
        } else {
            tree.visit(nearest({ x: x, y: y }, radius, sizeOffset, points.points, points.visited, tree));
        }

        return points;
    };

    /**
     *
     * @param radiusController
     * @return {d3.quadtree}
     */
    d3.quadtree.prototype.size = function(sizeController) {
        if (isFunction(sizeController)) {
            this._size = sizeController;
        }
        return this;
    };

    /**
     *
     * @param mouse
     * @param radius
     * @param hits
     * @param visits
     * @param tree
     * @return {function(*, *, *, *, *): boolean}
     */
    function nearest(mouse, radiusOffset, sizeOffset, hits, visits, tree) {
        var r = radiusOffset,
            nx1 = mouse.x - r,
            nx2 = mouse.x + r,
            ny1 = mouse.y - r,
            ny2 = mouse.y + r;

        return function(quad, x1, y1, x2, y2) {
            if (!quad.length) {
                visits.push(quad.data);
                do {
                    if (quad.data) {
                        var x = mouse.x - tree._x(quad.data),
                            y = mouse.y - tree._y(quad.data),
                            l = mathSQRT(x * x + y * y);

                        if (l <= tree._size(quad.data) / 2 + sizeOffset) {
                            //offset 10
                            hits.push(quad.data);
                        }
                    }
                } while ((quad = quad.next));
            }
            return x1 > nx2 || x2 < nx1 || y1 > ny2 || y2 < ny1;
        };
    }

    function withinRect(extent, points, visited, tree) {
        let x0 = extent[0][0],
            y0 = extent[0][1],
            x3 = extent[1][0],
            y3 = extent[1][1];

        return function(quad, x1, y1, x2, y2) {
            if (!quad.length) {
                do {
                    var d = quad.data;
                    var x = tree._x(d),
                        y = tree._y(d);
                    visited.push(d);
                    if (x >= x0 && x < x3 && y >= y0 && y < y3) {
                        points.push(d);
                    }
                } while ((quad = quad.next));
            }
            return x1 >= x3 || y1 >= y3 || x2 < x0 || y2 < y0;
        };
    }
})(d3);

d3.selection.prototype.first = function() {
    return d3.select(this.nodes()[0]);
};
d3.selection.prototype.last = function() {
    return d3.select(this.nodes()[this.size() - 1]);
};

// remove all listeners
d3.selection.prototype.removeAllListeners = function() {
    let listeners;
    if ((listeners = this.node() && this.node().__on)) {
        listeners.forEach(listener => this.on(`.${listener.name}`, NULL));
    }
    return this;
};

// for identifying d3 selection
d3.selection.prototype.isD3Selection = true;
